INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('dietitian-moex-04674', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '對於嘌呤核苷酸（purinenucleotides）分解的敘述，下列何者正確？', '["人體內嘌呤核苷酸分解過程是由核苷酸（nucleotides）降解為核苷（nucleosides），再由核苷降解 為鹼基，最後形成終產物", "人體內嘌呤核苷酸分解過程包括還原作用（reduction）與轉胺作用（transamination）", "人體內具有酵素可將嘌呤環狀結構打開而形成中間產物尿囊素（allantoin）", "人體內分解嘌呤之最終產物為尿素（urea）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04675', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於mRNA穩定性（mRNAstability）的敘述，下列何者正確？', '["降解反應通常從mRNA的5'' 端往3'' 端進行", "一般而言，細菌mRNA的半衰期相較於真核生物者長", "mRNA的降解速率通常較mRNA合成速率至少慢1/10", "mRNA分子上的二級結構可延緩被降解的速率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04676', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '檸檬酸循環代謝反應中那一步驟形成FADH ？ 2', '["α-酮基戊二酸（α-ketoglutarate）形成琥珀醯-輔酶A（succinylCoA）", "琥珀醯-輔酶A（succinylCoA）形成琥珀酸（succinate）", "琥珀酸（succinate）形成延胡索酸（fumarate）", "蘋果酸（malate）形成草醯醋酸（oxaloacetate）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04677', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列那些酵素所催化的反應會產生NADPH？①glyceraldehyde-3-phosphatedehydrogenase', '["pyruvatedehydrogenase", "glucose-6-phosphatedehydrogenase", "isocitratedehydrogenase ⑤malicenzyme", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04678', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於血糖的調控，下列敘述何者錯誤？', '["腦下腺機能不全時，因會影響到促腎上腺皮質素（ACTH）的分泌，故會增加葡萄糖耐受性", "當有壓力時，會刺激腎上腺素的分泌，並活化磷酸化酶，導致肝臟與肌肉之肝醣分解作用", "升糖素會刺激骨骼肌中的胺基酸之異化作用，增加糖質新生作用", "胰島素並不會直接影響肝臟獲取（uptake）葡萄糖，但會調節糖解、肝醣合成及糖質新生相關酵 素的作用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04679', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於肝醣的敘述，下列何者錯誤？', '["vonGierke氏症是一種肝醣儲存疾病，肝醣會聚集在肝細胞及腎小管", "cAMP 是主要調控或整合肝醣分解及肝醣合成的重要因子", "肌肉與肝臟中的肝醣，分解的最終產物均為葡萄糖，用以維持血糖濃度", "經12~18小時的禁食後，肝臟中的肝醣幾乎耗盡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04680', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者是連結糖解作用、檸檬酸循環的重要化合物？', '["乙醯輔酶A（acetyl-CoA）", "葡萄糖6-磷酸（glucose-6-phosphate）", "β-羥基丁醯-輔酶A（β-hydroxybutyryl-CoA）", "丙酮酸（pyruvicacid）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04681', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者脂肪激素（adipokine）可促進肝臟與骨骼肌胰島素敏感性（insulinsensitivity）？', '["瘦素（leptin）", "脂聯素（adiponectin）", "胰島素（insulin）", "升糖素（glucagon）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04682', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '肝臟缺乏下列何者酵素，使得酮體無法代謝為乙醯輔酶A（acetyl-CoA），故無法以酮體作為能量 來源？', '["HMG-CoAlyase", "β-3-hydroxybutyrate dehydrogenase", "β-3-ketoacyl-CoA transferase", "thiolase"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04683', 'dietitian', 'dietitian-moex-112-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於磷酸甘油酯（phosphatidylglycerol）生化代謝的敘述，下列何者錯誤？', '["磷酸甘油酯的前驅物是glycerol-3-phosphate與fattyacyl-CoA", "glycerol-3-phosphate可由甘油耗掉一分子NADH後生成", "當磷酸甘油酯經 phosphatase 轉換成 phosphatidic acid 後，再加上膽鹼後可轉換成卵磷脂 （phosphatidylcholine）", "當磷酸甘油酯經 phosphatase 轉換成 phosphatidicacid 後，再加上acyl-CoA可轉換成三酸甘油酯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:36+00:00", "source_pdf_sha1": "a95b04b12138", "answer_pdf_sha1": "2f7c57b169bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
